"""
mkt-christ commentary -- Jeremiah chapters 18-21
Run: python3 scripts/zc-christ-jeremiah-18-21.py

Christological focus per chapter:
  Ch18: Potter and clay — sovereign divine re-shaping; Christ as the potter who
    forms and reforms (Rom 9:20-21; Isa 64:8); conditional repentance principle
    (2 Pet 3:9); the Fifth Confession as type of Christ's intercessory prayers
    and the cross.
  Ch19: Broken clay flask — irreversible judgment (contrast with ch18's reformable
    clay); Tophet/Gehenna as NT judgment image; innocent blood as type of Christ's
    blood shed in the same valley's tradition.
  Ch20: Pashhur/Magor-Missabib oracle; Sixth Confession — the deepest prophetic
    suffering as type of Christ's suffering (fire in bones / Heb 12:1-2;
    pit-digging / Ps 22; the birth-curse as type of Gethsemane's anguish).
  Ch21: Deuteronomy's way-of-life/death presented through Zedekiah's siege; Christ
    as the true way of life (John 14:6); the inverted exodus formula as the cross;
    House of David / justice standard fulfilled in Christ.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # Never overwrite existing entries — safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
  "18": {
    "1": "<p>\"This is the word that came to Jeremiah from the LORD\" — the standard reception formula introduces the potter's house sign-act, one of the most Christologically resonant narratives in Jeremiah. The prophetic word that comes to Jeremiah in this chapter eventually points toward the Word made flesh, who himself is both the Potter and the vessel made new.</p>",
    "2": "<p>\"Get up and go down to the potter's house\" — the divine directive sends Jeremiah to observe a craftsman at work. The potter's house as the site of prophetic revelation anticipates the NT theme of encountering the divine in ordinary human labor and material. The incarnation itself is God \"going down\" to the place of human craftsmanship to speak through the lowliest of materials — flesh and clay.</p>",
    "3": "<p>\"He was there, working at the wheel (<em>ʾōbānāyim</em>).\" The image of the potter at the wheel — present, attentive, hands on the clay — is a picture of engaged, personal sovereignty. Christologically, this is the posture of the incarnate Son: not distant oversight but hands-on, present involvement in human material. The Word becoming flesh (John 1:14) is the ultimate going-down to the potter's wheel.</p>",
    "4": "<p>\"The clay vessel he was shaping was ruined in his hands; so he reworked it into another vessel, as seemed best to him.\" The key Christological content of the sign-act: the clay that does not cooperate is not discarded but remade. The sovereignty exercised here is not destructive but reformative. Christologically, this is the logic of the new covenant: Israel's failure under the Sinai covenant does not end YHWH's purpose but leads to the new covenant's reformation of the same material. 2 Cor 5:17 (\"if anyone is in Christ, he is a new creation; the old has passed away, behold the new has come\") is the NT statement of the potter's reforming work applied to individuals through union with Christ.</p>",
    "5": "<p>\"Then the word of the LORD came to me\" — the transition from observation to divine interpretation. The prophetic sign-act is incomplete without the divine word that interprets it; the sign is the vehicle, the word is the content. Christologically, Jesus is both sign and word simultaneously: he is the sign of God's reign and also the one who interprets that sign with absolute authority (John 7:16-17).</p>",
    "6": "<p>\"Can I not deal with you as this potter has dealt with the clay, O house of Israel?\" The rhetorical question assumes its own answer — YHWH's potter-sovereignty over Israel is absolute and non-negotiable. Rom 9:20-21 cites this exact imagery: \"Will what is molded say to its molder, 'Why have you made me like this?' Has the potter no right over the clay?\" Paul deploys the potter-clay argument in the context of Israel's rejection and the inclusion of Gentiles — the very context of Jeremianic prophecy. Christ himself is the supreme vessel formed by the Father, and through union with him, believers become what Paul calls \"God's workmanship (<em>poiēma</em>), created in Christ Jesus for good works\" (Eph 2:10) — the Greek <em>poiēma</em> (workmanship/poem/crafted thing) echoes the potter-craft imagery.</p>",
    "7": "<p>\"There are times when I pronounce concerning a nation or kingdom that I will uproot it, tear it down, and destroy it.\" The conditional character of prophetic judgment — YHWH reserves the right to revoke announced judgment — is here stated as a universal principle governing all nations. Christologically, this conditionality reflects the divine character that reaches its fullest expression in the cross: God could have executed the irreversible judgment of ch19's broken flask against all of humanity, but instead entered history in Christ to provide the path of repentance (v8).</p>",
    "8": "<p>\"But if that nation turns from its evil, I will relent concerning the disaster I intended to bring on it.\" The repentance-and-relenting principle is the most explicit OT statement of divine responsiveness to human turning. 2 Pet 3:9 (\"not wishing that any should perish, but that all should reach repentance\") is the NT formulation of this same divine disposition. Christologically, the cross is God's definitive act of opening a way of repentance where the demands of justice seemed to close every door. The \"relenting\" of v8 is ultimately grounded in Christ's atoning work — the justice that must be met is met, enabling the mercy that was always the divine desire.</p>",
    "9": "<p>\"And there are times when I declare concerning a nation or kingdom that I will build and plant it\" — the positive side of the conditional: YHWH is not only the God who withholds judgment but the one who announces prosperity, and that announcement too is contingent on human response. Christologically, the unconditional new covenant (Jer 31:31-34) supersedes this conditionality for the covenant community: in Christ, the building-and-planting is secured by the divine promise rather than contingent on human performance (Heb 6:13-20).</p>",
    "10": "<p>\"But if that nation does evil in my sight and does not obey me, I will relent of the good I said I would do for it.\" The symmetry of vv7-10 — conditionality works in both directions — establishes the relational, rather than mechanical, character of divine governance. Christologically, the new covenant removes this reverse-conditionality for those in Christ: Rom 8:38-39 declares nothing can separate believers from God's love in Christ Jesus. The conditionality of vv7-10 belongs to the old covenant order; the new covenant's unconditional security is grounded in Christ's permanent standing before the Father.</p>",
    "11": "<p>\"I am shaping disaster against you right now and devising a plan against you. Turn back, each of you from your evil way.\" YHWH as active, present Potter reshaping the clay of judgment — the present-tense urgency. The call to turn back is the OT form of the gospel's call to repentance. Christologically, Jesus opens his public ministry with the same urgent call: \"The kingdom of God is at hand; repent and believe in the gospel\" (Mark 1:15). The potter's \"right now\" is the same urgency Paul expresses: \"Behold, now is the favorable time; behold, now is the day of salvation\" (2 Cor 6:2).</p>",
    "12": "<p>\"But they say: It is useless! We will follow our own plans and act according to the stubborn evil of our own hearts.\" The response of defiant self-determination — refusing the potter's reforming hand — is the posture that makes judgment irreversible. Christologically, this defiance is precisely what Jesus laments over Jerusalem (Matt 23:37: \"How often would I have gathered your children together... and you were not willing!\"). The refusal of the reforming hand is the form of human sin that the cross addresses: Christ does not force the clay but enters into the consequence of clay that refused to be remade.</p>",
    "13": "<p>\"Ask around among the nations — who has ever heard anything like this?\" The unprecedented nature of Israel's apostasy — more shocking than any pagan behavior — is the inverse of Israel's unique covenant calling. Christologically, Jesus uses similar comparative logic: \"It will be more tolerable on the day of judgment for the land of Sodom than for you\" (Matt 11:24). Those who have received more revelation bear greater responsibility — the unique horror of Israel's rejection of YHWH finds its climactic expression in the rejection of YHWH's own Son.</p>",
    "14": "<p>\"Does the snow of Lebanon ever leave the mountain crags? Do the cold streams ever run dry?\" The natural world's consistency serves as the contrasting measure for Israel's inconstancy. Snow remains on Lebanon; streams maintain their course; but Israel abandoned the living water (2:13). Christologically, the natural constancy that Israel violated finds its answer in Christ, who is \"the same yesterday and today and forever\" (Heb 13:8). The reliable streams that Israel did not learn from are the OT image of Christ's own unchanging faithfulness.</p>",
    "15": "<p>\"Yet my people have forgotten me; they burn offerings to worthless idols. They have stumbled off the ancient paths.\" The ancient paths (<em>nĕtîḇôt ʿôlām</em>) from which Israel has strayed are the covenant ways of YHWH. Christologically, Christ presents himself as the path from which no true disciple strays: \"I am the way\" (John 14:6). The stumbling off the ancient path in Jer 18:15 anticipates the NT's invitation back to the eternal way through the one who is himself the way.</p>",
    "16": "<p>\"They have made their land a desolation, a thing to be hissed at forever.\" The desolation-formula (<em>šammâ</em>) appears here as the self-caused consequence of following the wrong paths. Christologically, the hissing that passes by Jerusalem's desolation anticipates the mocking at the cross: those who passed by \"wagged their heads\" and mocked (Matt 27:39-40; Ps 22:7). The desolation of Jerusalem and the desolation of the crucified Christ are typologically linked — in both cases the mockery of passersby reveals the depth of the covenant people's shame.</p>",
    "17": "<p>\"Like a scorching east wind I will scatter them before the enemy; I will show them my back, not my face, in the day of their calamity.\" The divine <em>ʿōrep</em> (back, neck) turned toward Israel — YHWH withdrawing his face — is the covenant curse of abandonment. Christologically, the cry of dereliction at the cross (Matt 27:46: \"My God, my God, why have you forsaken me?\") is the ultimate instance of the divine face being hidden. Christ experiences the full covenant curse of the hidden face — which Israel's sin had earned — so that those who trust him are never forsaken (Heb 13:5: \"I will never leave you nor forsake you\").</p>",
    "18": "<p>\"Come, let us make plans against Jeremiah.\" The conspiracy of the religious and intellectual establishment against the faithful prophet directly prefigures the conspiracy against Jesus. Jeremiah's opponents cite the institutional guarantors of truth: \"instruction will still come from the priests, counsel from the wise, and a word from the prophets\" — implying that Jeremiah is expendable because the institutions will continue without him. Jesus's enemies use the same institutional reasoning (John 11:48-50: \"the Romans will come and take away both our place and our nation\... it is better that one man die for the people\"). The prophetic victim of institutional conspiracy is the OT type; Christ is the fulfillment.</p>",
    "19": "<p>\"Give attention to me, O LORD; listen to what my adversaries are saying.\" The Fifth Confession opens (vv19-23) with Jeremiah's appeal for divine attention to his suffering. The prophet who pleaded for the people now pleads for himself against those who repay his intercession with persecution. Christologically, the pattern of intercession repaid with conspiracy is the pattern of Christ's passion: he prayed for his people (John 17; Luke 23:34) and was killed for it. Ps 35:12 (\"They repay me evil for good\") and Ps 109:4 (\"in return for my love they accuse me\") are the same pattern that Jeremiah voices here.</p>",
    "20": "<p>\"Should good be paid back with evil? Yet they have dug a pit for my life.\" The pit (<em>šûḥâ</em>) dug for Jeremiah echoes Ps 7:15; 35:7; 57:6 — the conspiracy to trap and kill the innocent. \"Remember how I stood before you and pleaded for them\" — the intercessory faithfulness that is repaid with murderous conspiracy. Christologically, Jesus's greatest act of intercession (the cross) is the act by which his conspirators believed they were eliminating him. The pit dug for Jeremiah is the OT type of the tomb prepared for Christ — in both cases the pit becomes the place from which YHWH/God delivers (Ps 16:10; Acts 2:31).</p>",
    "21": "<p>\"Therefore hand their children over to famine... let their men be struck down by plague.\" The imprecatory prayer of vv21-23 is Jeremiah's most extreme call for judgment on his enemies. This is the most difficult text in the Confessions for Christian readers. Christologically, it is read as the voice of the old covenant justice-demand, which Christ absorbs and redirects at the cross: rather than imprecating judgment on others, Christ absorbs judgment for others (Luke 23:34: \"Father, forgive them, for they do not know what they are doing\"). The imprecation of Jer 18:21 and the intercession of Luke 23:34 stand as the polar contrast between old-covenant prophetic response and Christ's new-covenant response to murderous conspiracy.</p>",
    "22": "<p>\"Let a cry be heard from their houses when you bring marauders against them without warning; for they have dug a pit to trap me and laid snares for my feet.\" The pit and snare imagery recalls the psalmic tradition of the righteous sufferer (Ps 22; 35; 69). Christologically, the pit/snare complex surrounding the faithful prophet is a type of the suffering of the Righteous One that finds its fullest form in Christ's passion. Ps 69 — one of the most heavily cited psalms in the passion narratives — uses precisely this language (Ps 69:2: \"I sink in deep mire where there is no foothold\").</p>",
    "23": "<p>\"But you, O LORD, know all their schemes against my life. Do not forgive their guilt or erase their sin from your sight.\" The closing imprecation — a stark contrast to Jesus's \"Father, forgive them\" — marks the limit of the old covenant prophetic response. Paul addresses this limit directly in Rom 12:19-21 (\"Beloved, never avenge yourselves, but leave it to the wrath of God\") and Matt 5:44 (\"Love your enemies and pray for those who persecute you\") is Jesus's own surpassing of the old covenant standard. Christ fulfills Jeremiah's prophetic office at this point not by repeating the imprecation but by transforming it into intercession — the new covenant's definitive answer to the problem of unjust suffering.</p>"
  },
  "19": {
    "1": "<p>\"Go and buy a potter's clay flask (<em>baqbûq</em>).\" The shift from ch18's malleable unfired clay to the fired clay flask is the key Christological contrast: ch18 is reformable clay; ch19 is fired pottery — irreversible once broken. The divine command to buy the flask (a specific, commercially available vessel, not a lump of clay on the wheel) introduces the sign-act of irreversible judgment. Christologically, this irreversibility mirrors the eschatological judgment announced throughout the NT — the finality of judgment on those who reject the gospel's invitation (Heb 10:26-27; Rev 20:11-15).</p>",
    "2": "<p>\"Go out to the valley of Ben-hinnom, at the entrance of the Potsherd Gate.\" The valley of Ben-hinnom (<em>gê ben-hinnōm</em>) becomes <em>Gehenna</em> in the NT — the Greek transliteration of the Hebrew valley name. Jesus uses <em>Gehenna</em> more than any other NT figure as the image for final judgment (Matt 5:22, 29-30; 10:28; 18:9; 23:33; Mark 9:43-48; Luke 12:5). By conducting the sign-act of irreversible judgment in this specific valley, Jeremiah establishes the symbolic geography that Christ inherits and deepens. The broken flask at the Potsherd Gate in the Hinnom Valley is the OT origin of Jesus's Gehenna-language.</p>",
    "3": "<p>\"I am going to bring such a disaster on this place that the ears of everyone who hears about it will ring.\" The <em>ṣillûl ʾoznāyw</em> (ringing/tingling of ears) is the formula for unprecedented horror (1 Sam 3:11; 2 Kings 21:12). Christologically, the unprecedented judgment announced for Jerusalem in 586 BCE is the type of the unprecedented judgment Jesus announces for Jerusalem in 70 CE (Luke 21:22-23: \"there will be great distress on the land and wrath against this people\"). The ears-ringing horror is repeated across the typological levels.</p>",
    "4": "<p>\"Because they have abandoned me and made this a foreign place... and have filled this place with the blood of the innocent.\" The twofold indictment — abandoning YHWH, shedding innocent blood — is the double covenant violation that makes judgment irreversible. Christologically, the blood of the innocent that fills the valley anticipates the innocent blood shed at the cross — but with a decisive reversal. The blood of Abel cries for judgment (Gen 4:10; Heb 12:24); the blood of Jesus speaks \"better than the blood of Abel,\" not crying for judgment but securing forgiveness. The valley of innocent blood becomes, in Christ, the ground of redemption rather than condemnation.</p>",
    "5": "<p>\"They have built the high places of Baal to burn their sons in the fire... something I never commanded, never decreed, something that never even entered my mind.\" The triple negation of child sacrifice — the most extreme form of idolatrous covenant violation — is YHWH's absolute disavowal of the practice. Christologically, the contrast between this abhorred child-burning and the Father's offering of his Son is total: the pagan child-sacrifice is rejected as alien to YHWH's character; the Father's offering of Christ is precisely the expression of his deepest covenant love (John 3:16). The idolatrous burning of children to Baal is the grotesque parody of what YHWH himself does in giving his Son — except that the Father gives his Son to save life, not to extinguish it.</p>",
    "6": "<p>\"Therefore the days are coming when this place will no longer be called Tophet or the valley of Ben-hinnom, but the valley of Slaughter.\" The renaming of Tophet as the \"valley of Slaughter\" is a prophetic omen-name: the place of false sacrifice becomes the place of true judgment. Christologically, the NT's use of <em>Gehenna</em> (from Ben-hinnom) as the image of final judgment completes this renaming: the valley where Israel played at sacrifice (child-burning) becomes the symbolic site of genuine divine reckoning. Jesus's Gehenna-warnings are the fullest development of this Jeremianic renaming.</p>",
    "7": "<p>\"I will empty out the plans of Judah and Jerusalem in this place.\" The verb <em>bāqaq</em> (to empty) is the same root as <em>baqbûq</em> (the flask of v1) — YHWH will empty out Judah's plans just as the flask will be emptied and then smashed. The wordplay (<em>baqbûq/bāqaq</em>) is the sign-act's own linguistic interpretation. Christologically, the emptying of human plans before divine judgment mirrors the emptying of Christ at the incarnation (Phil 2:7: <em>ekenōsen</em>, \"he emptied himself\") — except that Christ's self-emptying is voluntary and redemptive, while Judah's emptying is involuntary and penal.</p>",
    "8": "<p>\"I will make this city a scene of horror and contempt; all who pass by it will be horrified and will hiss in scorn.\" The formula of horror and hissing recurs from 18:16. Christologically, the passersby who mock the ruined city (Lam 1:12: \"Is it nothing to you, all you who pass by?\") are a type of the passersby who mock the crucified Christ (Matt 27:39: \"those who passed by derided him, wagging their heads\"). The lament formula of the destroyed city becomes the lament formula of the suffering servant.</p>",
    "9": "<p>\"I will make them eat the flesh of their sons and daughters.\" The siege-cannibalism announced as the extreme of covenant curse (Deut 28:53-57; Lam 4:10) is the most shocking element of the oracle. Christologically, this extreme physical curse is the negative context that makes Jesus's eucharistic language scandalous and profound in John 6:53-56: \"Unless you eat the flesh of the Son of Man and drink his blood, you have no life in you.\" Where covenant violation produces the horror of literal cannibalism in the siege, the new covenant produces the mystery of eucharistic communion — feeding on the life of Christ rather than destroying one another's lives.</p>",
    "10": "<p>\"Then break the flask in front of the men who have come with you.\" The performative destruction of the flask before witnesses is a legal and prophetic act — a sign-act that enacts the word it illustrates. Christologically, the public nature of the sign-act (\"in front of the men\") anticipates the public nature of the cross: Christ was crucified openly, \"publicly portrayed as crucified\" (Gal 3:1), not in private. The sign-act performed before witnesses enacts the prophetic word; the cross enacted before witnesses fulfills the prophetic word.</p>",
    "11": "<p>\"I will smash this people and this city just as one smashes a potter's vessel, so that it can never be repaired again.\" The irreparability (<em>lōʾ yûḵal lĕhērāpēʾ ʿôd</em>, it cannot be repaired again) is the key contrast with ch18: the unfired clay can be remade; the fired and broken flask cannot. Christologically, this irreparability is the language of eschatological judgment (Rev 2:27: \"as when earthen pots are broken in pieces\"; Rev 19:15: Jesus smashes the nations with a rod of iron). The broken flask that cannot be repaired is the OT type of the final judgment that cannot be reversed.</p>",
    "12": "<p>\"This is what I will do to this place and its inhabitants... I will make this whole city like Tophet.\" The scope extends from the specific site (Tophet) to the whole city — the sign-act becomes a comprehensive oracle. Christologically, the expansion from a specific place to the whole city mirrors the NT's expansion of judgment and salvation from specific to universal: Christ's death at a specific place (Golgotha, outside Jerusalem) becomes the definitive event for the whole world (John 12:32: \"when I am lifted up from the earth, I will draw all people to myself\").</p>",
    "13": "<p>\"The houses of Jerusalem and the houses of the kings of Judah will be defiled just like Tophet — all the houses on whose rooftops they burned incense to all the starry host of heaven.\" The rooftop incense to the host of heaven (astral worship) is the Babylonian-influenced cult that penetrated even the royal houses. Christologically, this worship of created cosmic powers (stars and astral deities) is precisely what Paul addresses as the enslaved state from which Christ liberates (Gal 4:3, 9: \"weak and worthless elementary principles... enslaved to those that by nature are not gods\"; Col 2:8, 20). The cosmic powers worshiped on Jerusalem's rooftops are the OT form of the \"elemental spirits\" that Christ disarmed at the cross (Col 2:15).</p>",
    "14": "<p>\"Jeremiah came back from Tophet, where the LORD had sent him to prophesy, and stood in the court of the LORD's temple.\" The prophetic return from the place of enacted judgment to the temple court — to speak the same word in the most sacred space — mirrors the pattern of prophetic courage that Christ embodies in his temple-cleansing (Matt 21:12-13; John 2:13-17). The prophet who proclaims judgment in the valley then moves to the temple; Jesus who drives out the money-changers in the temple uses the same prophetic-judgment vocabulary: \"My house shall be called a house of prayer, but you are making it a den of thieves\" — citing Jer 7:11.</p>",
    "15": "<p>\"I am going to bring upon this city and all its surrounding towns every disaster I have announced against them, because they have stubbornly refused to listen to my words.\" The summary statement of irreversible judgment due to stubborn refusal is the final word of the Tophet oracle. Christologically, Jesus uses the same \"stubbornly refused\" language in his final lament over Jerusalem: \"O Jerusalem, Jerusalem... How often would I have gathered your children together... and you were not willing!\" (Matt 23:37). The accumulation of refused prophetic words reaches its climax in the refusal of the Word himself.</p>"
  },
  "20": {
    "1": "<p>Pashhur son of Immer, the chief temple officer, represents the institutional religious establishment in its most direct confrontation with Jeremiah's prophetic ministry. The name Pashhur (possibly meaning \"prosperity on every side\") will be inverted into a curse-name (v3). Christologically, the religious official who arrests and beats the prophet prefigures Caiaphas and the Sanhedrin who arrest and try Jesus (Matt 26:57-67). In both cases the institutional religious authority violently opposes the one YHWH sent.</p>",
    "2": "<p>\"Pashhur had Jeremiah the prophet beaten and put in the stocks at the Upper Benjamin Gate.\" The beating (<em>hikkâ</em>) and public humiliation (stocks, <em>maḥpeket</em>) of the prophet for speaking YHWH's word is the OT pattern of prophetic suffering. Christologically, Jesus's beating and public humiliation at the hands of the religious authorities (Matt 27:26-31; John 19:1-3) is the fulfillment of this pattern. The prophet beaten for speaking the divine word becomes the type of the Son beaten for being the divine Word.</p>",
    "3": "<p>\"The LORD has not named you Pashhur, but Magor-Missabib — Terror-on-Every-Side.\" The prophetic omen-name inversion: Pashhur's pleasant name is replaced by the terror-judgment name that Jeremiah himself has been applying to Judah (6:25; 46:5). Christologically, the naming of the persecutor with the judgment-name he sought to silence recalls Jesus's own naming of opponents: \"Brood of vipers\" (Matt 23:33), \"Whitewashed tombs\" (Matt 23:27) — the one who is persecuted has the authority to rename his persecutors with the truth of their condition.</p>",
    "4": "<p>\"I am going to make you a terror to yourself and to all your friends.\" The oracle against Pashhur turns the institutional persecutor's own security against him — the very power-structure he defended will be the instrument of his destruction. Christologically, this reversal anticipates the pattern of Acts: the Sanhedrin that condemned Jesus becomes the institution that loses its own members to the gospel (Acts 6:7: \"a great many of the priests became obedient to the faith\"). The persecutors of the prophet become, in many cases, recipients of the very word they tried to silence.</p>",
    "5": "<p>\"I will also hand over all the wealth of this city... to their enemies.\" The comprehensive confiscation of Jerusalem's treasures to Babylon is the covenant-curse consequence of institutional unfaithfulness. Christologically, the stripping of institutional wealth and prestige echoes Jesus's prediction of Jerusalem's complete desolation (Matt 24:2: \"there will not be left here one stone upon another that will not be thrown down\"). The wealth that the temple establishment tried to protect by killing the prophet is precisely what is lost when the prophet is silenced.</p>",
    "6": "<p>\"And you, Pashhur, with everyone in your household, will go into exile. You will go to Babylon, and there you will die.\" The personal exile-oracle against Pashhur extends to his entire household and concludes with death in exile — which is also the fate of the false prophets he supported. Christologically, the judgment pronounced on the persecutor is the OT form of Jesus's judgment-word against those who kill the prophets: \"Truly, I say to you, all these things will come upon this generation\" (Matt 23:36). Condemnation follows the killers of prophets across generations.</p>",
    "7": "<p>\"O LORD, you deceived me, and I let myself be deceived; you overpowered me and you won.\" The Sixth Confession opens with the most extreme accusation in the Psalter/Prophetic tradition against YHWH — the language of seduction/deception (<em>pittîtanî</em>, Piel of <em>pātâ</em>, used for erotic seduction in Exod 22:16; Judg 14:15). Jeremiah accuses YHWH of luring him into the prophetic office and then leaving him to suffer its consequences. Christologically, this raw prophetic cry of abandonment is the OT form of the cry of dereliction: \"My God, my God, why have you forsaken me?\" (Matt 27:46; Ps 22:1). Jesus takes this cry further — not mere accusation but the actual experience of divine abandonment that Jeremiah only feared. Heb 5:7-8 (\"in the days of his flesh, Jesus offered up prayers and supplications, with loud crying and tears\") applies this confessional pattern to Christ's passion prayer.</p>",
    "8": "<p>\"Every time I speak, I have to cry out — 'Violence! Destruction!' — and the word of the LORD has become for me nothing but reproach and mockery all day long.\" The word of YHWH that Jeremiah cannot escape becomes the source of his reproach. Christologically, John 1:11 (\"he came to his own, and his own people did not receive him\") and Heb 13:13 (\"let us go to him outside the camp and bear the reproach he endured\") identify Christ as the supreme bearer of reproach for speaking and being the divine word. The <em>ḥerpâ</em> (reproach, mockery) of v8 is the same <em>ḥerpâ</em> that Ps 69:7-9, 20 identifies as the central suffering of the righteous sufferer — cited in the NT passion tradition (Rom 15:3; John 2:17).</p>",
    "9": "<p>\"When I think, 'I will not mention him, I will speak in his name no more,' then there is in my heart something like a burning fire shut up in my bones.\" The burning-fire-in-the-bones is the most vivid description of prophetic compulsion in the OT — the word of YHWH is not an option Jeremiah can refuse, even when it costs him everything. Christologically, Heb 12:1-2 (\"looking to Jesus, the founder and perfecter of our faith, who for the joy set before him endured the cross, despising the shame\") describes Christ's own movement through suffering by means of a fixed purpose that could not be extinguished. Jesus's statement in Luke 12:49 (\"I came to cast fire on the earth, and would that it were already kindled!\") echoes the burning-fire compulsion — the mission could not be held back. John 4:34 (\"My food is to do the will of him who sent me and to accomplish his work\") expresses the same irresistible forward movement.</p>",
    "10": "<p>\"For I hear many people whispering, 'Terror on every side! Report him — let us report him!' All my trusted friends are waiting for me to slip.\" The betrayal by trusted friends (<em>ʾănšê šĕlōmî</em>, lit. men of my peace) anticipates Ps 41:9 (\"even my close friend in whom I trusted, who ate my bread, has lifted his heel against me\") — cited by Jesus in John 13:18 for Judas's betrayal. The pattern of betrayal by trusted friends in Jer 20:10 is the same pattern that Jesus identifies as the specific form his betrayal will take. The intimate betrayal is the darkest dimension of prophetic suffering, and Christ's experience of it is the fulfillment of both Jeremiah's and the psalmist's anticipation.</p>",
    "11": "<p>\"But the LORD is with me like a mighty and terrible warrior; therefore my persecutors will stumble and not prevail.\" The divine warrior (<em>gibbôr ʿārîṣ</em>, mighty terrible one) who is Jeremiah's champion is the positive anchor amid the Confession's anguish. Christologically, this confident assertion of divine vindication — in the middle of the deepest prophetic suffering — anticipates Phil 2:9-11 (\"therefore God has highly exalted him and bestowed on him the name that is above every name\"). The divine warrior who vindicates Jeremiah against his persecutors is the Father who vindicates Christ against death itself. The persecutors who stumble and do not prevail are the precise language of the resurrection's reversal.</p>",
    "12": "<p>\"O LORD of hosts, who tests the righteous and sees the innermost being — the heart and mind — let me see your vengeance on them, for to you I have committed my case.\" The appeal to YHWH as the one who sees the <em>klāyôt wālēḇ</em> (kidneys/heart, the innermost self) is the appeal to the divine judge who sees what human courts cannot. Christologically, Rev 2:23 attributes this same omniscient inner-seeing to the risen Christ: \"I am he who searches mind and heart\" — Jesus takes YHWH's prerogative of omniscient judgment as his own. The case committed to YHWH in Jer 20:12 is the case committed to the Father by Christ in Luke 23:46 (\"Father, into your hands I commit my spirit\").</p>",
    "13": "<p>\"Sing to the LORD! Praise the LORD! For he has rescued the life of the poor from the hand of evildoers.\" The sudden eruption of praise — after the depths of vv7-12 — is the structural pattern of the Individual Lament psalms (Ps 22: anguish → confidence → praise; Ps 69: complaint → trust → praise). Christologically, this movement from dereliction to praise is the passion-resurrection pattern: the cry of abandonment (v7 = Matt 27:46) gives way to the praise of vindication (Heb 2:12: \"I will tell of your name to my brothers; in the midst of the congregation I will sing your praise\" — citing Ps 22:22, itself the praise-section of the lament that begins with the cry of dereliction). The \"rescued the life of the poor\" in v13 anticipates Acts 2:32 (\"God raised this Jesus\").</p>",
    "14": "<p>\"Cursed be the day I was born!\" The sudden reversal from praise (v13) to self-curse (vv14-18) is the most psychologically stark transition in Jeremiah. The birth-curse parallels Job 3:3-10 (Job's identical curse of his birth-day). Christologically, the wish that one had never been born — that the incarnation/birth had never happened — is the OT extreme of prophetic despair. But Christ's response to his own suffering is the exact inverse of the birth-curse: in Gethsemane (Matt 26:39) he says \"not as I will, but as you will\" — accepting the cup rather than cursing the day. The birth-curse of Jeremiah is the OT extreme that Christ's Gethsemane prayer refuses.</p>",
    "15": "<p>\"Cursed be the man who brought the news to my father — 'A son has been born to you!' — and made him so happy.\" The imprecation extends to the messenger of birth-joy — the very announcement of the prophet's birth is now cursed. Christologically, the contrast with the annunciations of the NT is total: the angel announces Jesus's birth with \"Fear not, for behold, I bring you good news of great joy\" (Luke 2:10) — precisely the birth-joy that Jeremiah curses. The cursed birth-announcement in Jeremiah is the OT shadow of the blessed birth-announcement in Luke 2. Christ's birth inaugurates the joy that Jeremiah's birth led only to suffering.</p>",
    "16": "<p>\"Let that man be like the cities the LORD destroyed without pity; let him hear a cry of distress in the morning and a battle alarm at noon.\" The curse invokes the destruction of Sodom and Gomorrah (\"the cities the LORD destroyed without pity\"). Christologically, Jesus himself uses Sodom as the standard of judgment (Matt 10:15; 11:23-24) — the most extreme OT image of divine wrath without pity. The fact that Jeremiah appeals to Sodom-level destruction as the standard for his personal distress measures the depths of his prophetic suffering.</p>",
    "17": "<p>\"Because he did not kill me in the womb, so that my mother would have been my grave.\" The wish for pre-birth death — that the womb had been a tomb — is the ultimate withdrawal of consent from the covenant mission. This is the anti-life cry that stands as the OT's darkest moment of prophetic despair. Christologically, it is also the most precise foil for the incarnation: Christ entered the womb voluntarily (Heb 10:5-7: \"a body you have prepared for me... I have come to do your will, O God\"). Where Jeremiah wishes the womb had been his tomb, Christ accepted the womb as his path to the tomb — and through the tomb to resurrection.</p>",
    "18": "<p>\"Why did I ever come out of the womb? All I have known is trouble and sorrow, and my life will end in disgrace.\" The closing cry of the Sixth Confession — unanswered, unresolved, without a restoration-word — is the most open-ended of the Confessions. It does not end in praise (contrast v13). Christologically, the unanswered cry is the OT type of Holy Saturday — the silence between the cry of dereliction (Good Friday) and the resurrection announcement (Easter Sunday). The Confessions' refusal to resolve this cry on its own terms is itself the theological statement that only the resurrection can answer what v18 asks.</p>"
  },
  "21": {
    "1": "<p>\"This is the word that came to Jeremiah from the LORD when King Zedekiah sent Pashhur son of Malkijah and the priest Zephaniah son of Maaseiah to him.\" The royal delegation to Jeremiah at the crisis point of the Babylonian siege (588 BCE) marks the transition from the Confessions (chs 11-20) to the royal oracles (chs 21-24). The same establishment that persecuted Jeremiah now seeks his prophetic counsel. Christologically, this pattern of seeking the prophet's word in crisis after rejecting it in peace is the pattern Jesus identifies: \"You will not see me until you say, 'Blessed is he who comes in the name of the Lord'\" (Matt 23:39) — the recognition that comes too late.</p>",
    "2": "<p>\"Please seek a word from the LORD for us, because Nebuchadnezzar king of Babylon is attacking us. Perhaps the LORD will do something miraculous for us.\" Zedekiah's request invokes the <em>môpēt</em> (miracle, wonder) pattern of the exodus — \"perhaps YHWH will do one of his wonders\" — in hopes of a Hezekiah-style deliverance (2 Kings 19:35). Christologically, this demand for a miraculous sign in crisis is the pattern Jesus refuses: \"An evil and adulterous generation seeks a sign\" (Matt 12:39). The miracle requested is the wrong question; the right question is whether the asker has responded to the prophetic word that came in peace.</p>",
    "3": "<p>\"Jeremiah answered them: Tell Zedekiah this\" — the prophet's response is not the hoped-for assurance but the word of judgment. The prophetic daring required to deliver an oracle of doom to the besieged king mirrors the boldness Christ displays before Pilate (John 18:37: \"You say that I am a king. For this purpose I was born and for this purpose I have come into the world — to bear witness to the truth\"). Both Jeremiah before Zedekiah and Jesus before Pilate speak an uncomfortable truth rather than a comfortable falsehood.</p>",
    "4": "<p>\"I am going to turn back the weapons in your hands — the very weapons with which you are fighting the king of Babylon.\" The grotesque reversal: YHWH will redirect Judah's own weapons against herself. The military equipment meant for defense becomes the instrument of self-destruction through divine sovereign redirection. Christologically, the cross enacts the same reversal: the powers that executed Jesus used the instruments of death (the cross) only to find that the very death they inflicted became the instrument of their own defeat (Col 2:15: \"He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him\").</p>",
    "5": "<p>\"And I myself will fight against you with an outstretched hand and a mighty arm, in burning anger and fury and great wrath.\" The exodus formula inverted: the \"outstretched arm and mighty hand\" that delivered Israel from Egypt (Deut 4:34; 5:15; 7:19; 26:8) is now turned against Israel. Christologically, the inverted-exodus formula is the OT form of divine wrath that Christ absorbs on behalf of the new covenant people. Gal 3:13 (\"Christ redeemed us from the curse of the law by becoming a curse for us\") means that Christ takes the divine wrath that the inverted exodus formulas represent — so that for those in Christ, the formula is re-inverted: the mighty arm that was against us is now for us (Rom 8:31: \"if God is for us, who can be against us?\").</p>",
    "6": "<p>\"I will strike down everyone living in this city — both people and animals — and they will die from a terrible plague.\" The covenant-plague vocabulary (<em>deber</em>) is the Deuteronomic curse-fulfillment (Deut 28:21-22). The comprehensive judgment — people and animals alike — echoes the totality of judgment in the exodus plagues. Christologically, the totality of judgment here is what Christ's atonement addresses: not partial sin-coverage but comprehensive bearing of the curse that extends through the entire created order (Rom 8:19-22: \"the creation itself will be set free from its bondage to corruption\").</p>",
    "7": "<p>\"After that... I will hand over Zedekiah king of Judah, his officials, and those who survive... to Nebuchadnezzar king of Babylon, to their enemies who seek their lives. He will put them to the sword without pity, without mercy, without compassion.\" The threefold negation — no pity, no mercy, no compassion — is the polar opposite of the divine character of Exod 34:6-7. Christologically, this absence of divine compassion in judgment is what Christ absorbs in his passion: the cross is the place where divine mercy and divine wrath meet, where pity, mercy, and compassion operate precisely by placing their cost on the innocent one.</p>",
    "8": "<p>\"I am setting before you the way of life and the way of death.\" The Deuteronomic two-ways formula (Deut 30:15-19: \"I set before you today life and prosperity, death and destruction\") is applied to the immediate crisis: surrender to Babylon (counterintuitive life) or resist (apparent strength leading to death). Christologically, Jesus explicitly takes up the two-ways formula and applies it to himself: \"I am the way, the truth, and the life; no one comes to the Father except through me\" (John 14:6). The Jeremianic \"way of life\" is an external path to follow; Christ IS the way, the life itself. John 10:10 (\"I came that they may have life and have it abundantly\") is the definitive statement of what the Deuteronomic and Jeremianic two-ways formula always pointed toward.</p>",
    "9": "<p>\"Whoever stays in this city will die by the sword, famine, or plague; but whoever goes out and surrenders to the Chaldeans who besiege you will live — his life will be his prize.\" The counterintuitive way of life — surrendering to the enemy as the path to survival — requires trust in the prophetic word against all human instinct. Christologically, this is the pattern of the cross: \"For whoever would save his life will lose it, but whoever loses his life for my sake will find it\" (Matt 16:25). Surrendering to the Chaldean enemy to live is the OT type of surrendering oneself to the apparent defeat of the cross to gain resurrection life. The <em>nefesh lĕšallāl</em> (life as plunder/prize) of the one who surrenders is the OT image of the eternal life gained through faith in the crucified one.</p>",
    "10": "<p>\"For I have fixed my gaze on this city for disaster and not for good, declares the LORD.\" The divine fixing of the gaze (<em>śamtî pānay</em>, I have set my face) for disaster is the reverse of the priestly blessing (Num 6:25: \"the LORD make his face shine on you and be gracious to you\"). Christologically, the divine face set against Jerusalem is turned from its object and toward Christ at the cross — who receives the curse in himself so that the face of divine grace can turn toward those who were under judgment. Isa 53:3 (\"he was despised... as one from whom men hide their faces\") is the servant's experience of the hidden divine face that Jer 21:10 threatened.</p>",
    "11": "<p>\"And to the house of the king of Judah, say: Hear the word of the LORD.\" The transitional verse addresses the Davidic royal house specifically. Christologically, the address to \"the house of the king of Judah\" is the address to the lineage from which Christ descends (Matt 1:1-17; Luke 1:32-33: \"the Lord God will give to him the throne of his father David\"). The prophetic word to the Davidic house reaches its fulfillment in the one born in David's city (Luke 2:11) who is himself the definitive heir of David's throne.</p>",
    "12": "<p>\"House of David! This is what the LORD says: Administer justice every morning; rescue from the oppressor those who have been robbed, or my anger will break out like an unquenchable fire.\" The justice-standard addressed to the house of David — daily morning justice for the oppressed — is the covenant calling of the Davidic king. Christologically, this is the Davidic standard that only Christ fully meets: he is the one who \"proclaims justice to the nations\" (Matt 12:18-21, citing Isa 42:1-4), who \"has been anointed... to proclaim good news to the poor, to set at liberty those who are oppressed\" (Luke 4:18, citing Isa 61:1-2). Jesus's morning teaching in the temple (Luke 21:37-38: \"every day he was teaching in the temple\") is the fulfillment of the \"every morning\" standard of Davidic justice.</p>",
    "13": "<p>\"I am against you, Jerusalem — you who sit enthroned in the valley, on your rocky plateau... who say, 'Who can attack us? Who can breach our strongholds?'\" The pride of Jerusalem — trusting in her geographic and architectural defenses — is the self-confidence that YHWH opposes. Christologically, this is the form of institutional pride that Jesus confronts in his temple-cleansing and in his prediction of the temple's destruction (Matt 24:1-2). The \"Who can breach our strongholds?\" boast of the Jerusalem establishment in Jeremiah's day is the same boast implicit in the claim that the temple and its institutions are inviolable — a claim that both Jeremiah and Jesus reject.</p>",
    "14": "<p>\"I will punish you as your deeds deserve, declares the LORD. I will set fire to your forest — and it will burn up everything around you.\" The concluding judgment — fire consuming the palace-forest (<em>yaʿar</em> may refer to the House of the Forest of Lebanon, the royal armoury of 1 Kings 7:2) — is the OT form of the judicial fire that consumes what does not endure. Christologically, 1 Cor 3:13-15 uses the same \"fire\" imagery for the testing of human work on the day of judgment. But more immediately, the fire that burns Jerusalem's palace-forest is the fire that Jesus says he came to cast on the earth (Luke 12:49) — the purifying, consuming fire of divine judgment that the mission of Christ brings and that is the ultimate grounds for both the cross (where Christ absorbs the fire) and the final judgment (where all things are tested by fire).</p>"
  }
}

def main():
    existing = load_comm("christ", "jeremiah")
    merge_comm(existing, JEREMIAH)
    save_comm("christ", "jeremiah", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Jeremiah mkt-christ: {len(existing)} chapters, {total} verses total.")

if __name__ == "__main__":
    main()
